// Minimal Lambda handler using sharp
const AWS = require('aws-sdk');
const s3 = new AWS.S3();
const ddb = new AWS.DynamoDB.DocumentClient();
const sharp = require('sharp');
exports.handler = async (ev) => {
  const bucket = 'photos-uploads';
  const key = ev.Records[0].s3.object.key;
  const obj = await s3.getObject({Bucket: bucket, Key: key}).promise();
  const thumb = await sharp(obj.Body).resize(800,600).toBuffer();
  const thumbKey = key.split('.').slice(0, -1).join('.') + '_thumb.jpg';
  await s3.putObject({Bucket: 'photos-thumbs', Key: thumbKey, Body: thumb}).promise();
  await ddb.put({TableName: 'Photos', Item: {imageKey: key, thumbKey, ts: Date.now(), size: obj.ContentLength}}).promise();
};
```

