## Code Example

```javascript
// Idempotent processor using DynamoDB for deduplication
const AWS = require('aws-sdk');
const dynamodb = new AWS.DynamoDB.DocumentClient();

exports.handler = async (event) => {
  const failures = [];

  for (const record of event.Records) {
    const { tenantId, sequenceId, data } = JSON.parse(record.kinesis.data);
    const tableName = process.env.DDB_TABLE;

    try {
      // Check if sequence already processed
      const result = await dynamodb.get({
        TableName: tableName,
        Key: { tenantId, sequenceId }
      }).promise();

      if (result.Item) {
        continue; // Skip duplicate
      }

      // Process data...
      await processData(tenantId, data);

      // Mark as processed
      await dynamodb.put({
        TableName: tableName,
        Item: { tenantId, sequenceId, processedAt: Date.now() }
      }).promise();

    } catch (error) {
      failures.push({ itemIdentifier: record.kinesis.sequenceNumber });
    }
  }

  return { batchItemFailures: failures };
};
```

